let text = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';

text = text
  .replace(/^```(?:latex|tex)?\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

const start = text.indexOf('\\documentclass');
const end = text.lastIndexOf('\\end{document}');

if (start >= 0 && end > start) {
  text = text.substring(start, end + '\\end{document}'.length);
}

if (text.indexOf('\\documentclass') < 0 || text.indexOf('\\end{document}') < 0) {
  throw new Error('Response does not contain a valid LaTeX document. Received: ' + text.substring(0, 100));
}

const filename = $('Build prompt').item.json.filename;

return [
  {
    json: {
      tex: text,
      filename
    }
  }
];
